import os
import json
import hashlib
import argparse
from llama_index.indices.managed.llama_cloud import LlamaCloudIndex

def compute_sha256(file_path):
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest().lower()

def main():
    parser = argparse.ArgumentParser(description="LlamaCloud Incremental Ingestion Planner")
    parser.add_argument("--input-dir", required=True, help="Absolute path to the local source directory to scan.")
    parser.add_argument("--previous-state", required=True, help="Absolute path to a JSON file describing the previously-synced state.")
    parser.add_argument("--output", required=True, help="Absolute path of the JSON sync plan to write.")
    parser.add_argument("--index-name", required=True, help="The LlamaCloud index name to record in the plan.")
    parser.add_argument("--project-name", default="Default", help="The LlamaCloud project name to record in the plan.")

    args = parser.parse_args()

    input_dir = args.input_dir
    previous_state_path = args.previous_state
    output_path = args.output
    index_name = args.index_name
    project_name = args.project_name

    if not os.path.isdir(input_dir):
        print(f"Error: input directory not found: {input_dir}", file=sys.stderr)
        sys.exit(1)

    # Supported extensions
    supported_extensions = {".pdf", ".docx", ".pptx", ".txt", ".md", ".html"}

    # Load previous state
    previous_files = {}
    if os.path.exists(previous_state_path):
        try:
            with open(previous_state_path, "r") as f:
                prev_data = json.load(f)
                for f_info in prev_data.get("files", []):
                    f_name = f_info["file_name"]
                    ext = os.path.splitext(f_name)[1].lower()
                    if ext in supported_extensions:
                        previous_files[f_name] = f_info["sha256"]
        except (json.JSONDecodeError, KeyError, TypeError):
            pass

    # Scan current directory
    current_files = {}
    for entry in os.scandir(input_dir):
        if entry.is_file():
            ext = os.path.splitext(entry.name)[1].lower()
            if ext in supported_extensions:
                file_path = os.path.abspath(entry.path)
                size_bytes = entry.stat().st_size
                sha256 = compute_sha256(file_path)
                current_files[entry.name] = {
                    "file_name": entry.name,
                    "path": file_path,
                    "size_bytes": size_bytes,
                    "sha256": sha256
                }

    actions = {
        "add": [],
        "update": [],
        "unchanged": [],
        "delete": []
    }

    # ADD, UPDATE, UNCHANGED
    for file_name, info in current_files.items():
        if file_name not in previous_files:
            actions["add"].append(info)
        else:
            prev_sha = previous_files[file_name]
            if info["sha256"] == prev_sha:
                actions["unchanged"].append({
                    "file_name": file_name,
                    "sha256": info["sha256"]
                })
            else:
                actions["update"].append({
                    "file_name": info["file_name"],
                    "path": info["path"],
                    "size_bytes": info["size_bytes"],
                    "sha256": info["sha256"],
                    "previous_sha256": prev_sha
                })

    # DELETE
    for file_name, prev_sha in previous_files.items():
        if file_name not in current_files:
            actions["delete"].append({
                "file_name": file_name,
                "previous_sha256": prev_sha
            })

    # Sort each list alphabetically by file_name
    for key in actions:
        actions[key].sort(key=lambda x: x["file_name"])

    summary = {key: len(actions[key]) for key in actions}

    output_data = {
        "index_name": index_name,
        "project_name": project_name,
        "actions": actions,
        "summary": summary
    }

    with open(output_path, "w") as f:
        json.dump(output_data, f, indent=2)

