    summary = {key: len(actions[key]) for key in actions}

    output_data = {
        "index_name": index_name,
        "project_name": project_name,
        "actions": actions,
        "summary": summary
    }

    with open(output_path, "w") as f:
        json.dump(output_data, f, indent=2)

    print(f"Sync plan written to {os.path.abspath(output_path)}: add={summary['add']} update={summary['update']} unchanged={summary['unchanged']} delete={summary['delete']}")

if __name__ == "__main__":
    main()
